er-radius: 0px;" role="presentation">\r\n<table style="width: 100%;\r\nborder-collapse: collapse;" class="containerWrapper tbContainer" cellpadding="0" cellspacing="0" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th data-container="true" class="columnContainer" data-container-width="100" style="font-weight: normal; text-align: left; vertical-align: top; min-width: 5px; width: 580px; ;height: 0px;" role="presentation">\r\n<table width="100%" cellpadding="0" cellspacing="0" style="height: 100%;" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th class="inner" style="text-align: left; min-width: 5px; padding: 10px; vertical-align: top; word-wrap: break-word; word-break: break-word; font-weight: normal;" role="presentation">\r\n<div data-editorblocktype="Text" style="background-color: transparent; margin: 10px;"><p style="margin: 0px; padding: 0px; line-height: inherit; mso-line-height-rule: at-least; font-family: Arial, Verdana, sans-serif; font-size: 14px; color: #000; font-weight: normal; text-align: left;"><span style="font-size: 16px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;"><span style="font-weight: bold;">Would you like some assistance getting started?</span>&nbsp;<a href="https://public-usa.mkt.dynamics.com/api/orgs/1e56dbe2-1fcb-4e23-bd18-0898e86de843/r/XLznETTugE-d1FWUCYMAAAYAAAA?msdynmkt_target=%7B%22TargetUrl%22%3A%22https%253A%252F%252Fabout.ads.microsoft.com%252Fen%252Fget-started%252Fcontact-expert%252Funited-states%253Fs_cid%253Den-us-acq-other-src_ntr-sub_evergreen-flx_email8%22%2C%22RedirectOptions%22%3A%7B%225%22%3Anull%2C%221%22%3Anull%7D%7D&msdynmkt_digest=k4VVTUa%2Flk%2BHZGqu6gvy2UiOIZmcuTnU%2FkpeEKm1jGc%3D&msdynmkt_secretVersion=a3955a744d9049f88dd8bdc1907bf2bf" style="text-decoration: none; font-family: Arial, Verdana, sans-serif; font-size: inherit; font-weight: normal; color: #0082dd;"><span style="color: rgb(0, 120, 212); text-decoration: underline; font-size: 16px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;">Connect with a Microsoft Advertising expert &gt;</span></a></span><br></p></div></th>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</th>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</th>\r\n</tr>\r\n<!--[if gte mso 9]> <tr style="padding: 0px;mso-line-height-rule: exactly;line-height: 1px; background-color: rgb(242, 242, 242);" height="0"><td>&nbsp;</td></tr> <![endif]--></tbody>\r\n</table></div><div data-section="true" class="emptyContainer columns-equal-class wrap-section" style="margin: 0px; border-radius: 0px; background-color: rgb(225, 211, 199);"><!--[if gte mso 9]> </div><div style="background-color: transparent; border:none;"> <![endif]--><table class="outer" align="center" cellpadding="0" cellspacing="0" style="display: block;" role="presentation">\r\n<tbody>\r\n<!--[if gte mso 9]> <tr style="padding: 0px;mso-line-height-rule: exactly;line-height: 1px; background-color: rgb(225, 211, 199);" height="0"><td>&nbsp;</td></tr> <![endif]--><tr>\r\n<th style="padding: 10px 10px 0px; background-color: rgb(225, 211, 199); border-color: rgb(0, 0, 0); border-width: 0px; border-style: none; border-radius: 0px;" role="presentation">\r\n<table style="width: 100%;\r\nborder-collapse: collapse;" class="containerWrapper tbContainer" cellpadding="0" cellspacing="0" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th data-container="true" class="columnContainer" data-container-width="100" style="font-weight: normal; text-align: left; vertical-align: top; min-width: 5px; width: 580px; height: 0px; padding: 0px; background-color: rgba(0, 0, 0, 0);" role="presentation">\r\n<table width="100%" cellpadding="0" cellspacing="0" style="height: 100%;" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th class="inner" style="text-align: left; min-width: 5px; padding-right: 10px; padding-bottom: 0px; padding-left: 10px; vertical-align: top; word-wrap: break-word; word-break: break-word; background-color: rgba(0, 0, 0, 0); border-radius: 0px; font-weight: normal;" role="presentation">\r\n<div data-editorblocktype="Text" style="background-color: transparent; margin: 10px 10px 0px;"><p style="margin: 0px; padding: 0px; line-height: inherit; mso-line-height-rule: at-least; font-family: Arial, Verdana, sans-serif; font-size: 14px; color: #000; font-weight: normal; text-align: left;"><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;">†Offer details: Offer expires </span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-weight: bold;">Tuesday, June 30, 2026</span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;">. Valid only for new Microsoft Advertising customers in the United States who are first party recipients of the offer email. A new Microsoft Advertising customer is one that has not had an active Microsoft Advertising account before. Limit one promotional offer per new Microsoft Advertising customer. To redeem this offer, customer must create a new Microsoft Advertising account with a primary payment method on file. Once customer completes Microsoft Advertising new customer account setup and spends at least </span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-weight: bold;">$250</span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;"> on advertising charges excluding taxes, the promotional credit of </span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-weight: bold;">$500</span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;"> will automatically be applied toward additional advertising spend thereafter, until credit is exhausted or the offer expires. For prepay accounts: the minimum qualifying ad spend amount is deducted directly from prepay funds. For postpay threshold accounts: the primary payment method is charged to collect the minimum qualifying ad spend once the account threshold is met. Customers are responsible for the payment of any taxes incurred. If you create your Microsoft Advertising account in a different currency than the one in which your promotional credit has been awarded, the actual amount of the promotional credit may be subject to foreign currency fluctuations. Any portion of the credit not used within </span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-weight: bold;">ninety (90) days</span><span style="background-color: transparent; font-size: 10px; font-family: &quot;Segoe UI&quot;, Frutiger, &quot;Helvetica Neue&quot;, Arial, sans-serif;"> of credit award will expire and cannot be carried over or restored even if the Microsoft Advertising customer switches their payment method. If customer payment method fails, the promotional credit will not be applied. Microsoft Advertising will continue to run and accrue costs after any promotional credit has been exhausted. This offer may not be combined with any other offer, promotional code coupon or discount, separated, redeemed for cash, transferred, sold, or bartered. Microsoft, in its sole discretion, may close your account for any suspected abuse of this offer. Neither the original advertising qualifying spend nor the promotional credit are refundable, in whole or in part. See Microsoft Advertising Terms and Conditions for more details at sign-up. Other terms and conditions may apply. Microsoft reserves the right to cancel, change, or suspend this offer at any time without notice. Your offer may not cover spend accrued on campaigns run on Google Ads and Facebook Ads.</span></p></div></th>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</th>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</th>\r\n</tr>\r\n<!--[if gte mso 9]> <tr><td  style="font-size: 0px; line-height:0px;mso-line-height-rule: exactly; display: none !important; mso-hide:all;background-color: rgb(225, 211, 199);"><p style="font-size: 0px;height:0px; margin: 0px; padding:0;line-height: 0px; mso-line-height-rule: exactly; background-color: transparent;"><br/></p></td></tr> <![endif]--></tbody>\r\n</table></div><div data-section="true" class="emptyContainer columns-equal-class wrap-section" style="background-color: rgb(225, 211, 199);" data-idcontentblocksection="2205bbf1-1a53-f011-bec2-6045bd08d3ec" data-protected="true"><!--[if gte mso 9]> </div><div style="background-color: transparent; border:none;"> <![endif]--><table class="outer" align="center" cellpadding="0" cellspacing="0" style="display: block;" role="presentation">\r\n<tbody>\r\n<!--[if gte mso 9]> <tr style="padding: 0px;mso-line-height-rule: exactly;line-height: 1px; background-color: rgb(225, 211, 199);" height="0"><td>&nbsp;</td></tr> <![endif]--><tr>\r\n<th style="padding: 10px; background-color: rgb(225, 211, 199);" role="presentation">\r\n<table style="width: 100%;\r\nborder-collapse: collapse;" class="containerWrapper tbContainer multi" cellpadding="0" cellspacing="0" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th data-container="true" class="columnContainer" data-container-width="25" style="font-weight: normal; text-align: left; vertical-align: top; min-width: 5px; width: 145px; ;height: 0px;" role="presentation">\r\n<table width="100%" cellpadding="0" cellspacing="0" style="height: 100%;" role="presentation">\r\n<tbody>\r\n<tr>\r\n<th class="columnContainer inner" style="text-align: left; min-width: 5px; paddi