                     </tr>\r\n                      </tbody>\r\n                    </table>\r\n<!--[if (gte mso 9)|(IE)]></td></tr></table><![endif]-->\r\n                  </td>\r\n                </tr>\r\n              </tbody>\r\n              <tbody data-block-id="15" class="mceWrapper">\r\n                <tr>\r\n                  <td style="background-color:#ffffff" align="center" valign="top" class="mceSectionBody">\r\n                    <!--[if (gte mso 9)|(IE)]><table align="center" border="0" cellspacing="0" cellpadding="0" width="660" style="width:660px;"><tr><td><![endif]-->\r\n                    <table border="0" cellpadding="0" cellspacing="0" width="100%" style="max-width:660px" role="presentation">\r\n                      <tbody>\r\n                        <tr>\r\n                          <td style="background-color:#ffffff" class="mceWrapperInner" valign="top">\r\n                            <table align="center" border="0" cellpadding="0" cellspacing="0" width="100%" role="presentation" data-block-id="14">\r\n                              <tbody>\r\n                                <tr class="mceRow">\r\n                                  <td style="background-position:center;background-repeat:no-repeat;background-size:cover" valign="top">\r\n                                    <table border="0" cellpadding="0" cellspacing="0" width="100%" role="presentation">\r\n                                      <tbody>\r\n                                        <tr>\r\n                                          <td style="padding-top:0;padding-bottom:0" class="mceColumn" data-block-id="-8" valign="top" colspan="12" width="100%">\r\n                                            <table border="0" cellpadding="0" cellspacing="0" width="100%" role="presentation">\r\n                                              <tbody>\r\n                                                <tr>\r\n                                                  <td style="padding-top:0;padding-bottom:0;padding-right:0;padding-left:0" valign="top">\r\n                                                    <table width="100%" style="border:0;border-radius:0;border-collapse:separate">\r\n                                                      <tbody>\r\n                                                        <tr>\r\n                                                          <td style="padding-left:24px;padding-right:24px;padding-top:12px;padding-bottom:12px" class="mceTextBlockContainer">\r\n                                                            <div data-block-id="5" class="mceText" id="dataBlockId-5" style="width:100%">\r\n                                                              <p>Hey there,</p>\r\n\r\n                                                        \r\n\r\n                                                              <p>Google Cloud NEXT '26 has officially kicked off, and we're\r\n                                                                excited to launch the <a href="https://dev.to/devteam/tune-in-and-join-the-google-cloud-next-26-writing-challenge-1000-in-prizes-21bd?ahoy_click=true&t=7PYzwIKV1k9waajTLbYgjiEYZOje3ndX&s=-eoo1WOLuREfTamr7p0jShVp91jwBDWmNK9AuEyf3o0&u=https%253A%252F%252Fdev.to%252Fdevteam%252Ftune-in-and-join-the-google-cloud-next-26-writing-challenge-1000-in-prizes-21bd">Google\r\n                                                                  Cloud NEXT '26 Writing Challenge</a>.</p>\r\n\r\n                                                              <p><strong>Your mandate: explore the Google Cloud NEXT '26\r\n                                                                  announcements and pick the release, update, or\r\n                                                                  livestream session that speaks to you</strong>.</p>\r\n                                                              <p>Share your take with the community as a tutorial,\r\n                                                                reflection, opinion piece, or first-look guide. We want\r\n                                                                your perspective and insights, not just a summary.</p>\r\n\r\n                                                              \r\n\r\n\r\n                                                            </div>\r\n                                                          </td>\r\n                                                        </tr>\r\n                                                      </tbody>\r\n                                                    </table>\r\n                                                  </td>\r\n                                                </tr>\r\n                                                <tr>\r\n                                                  <td style="background-color:#ffffff;padding-top:12px;padding-bottom:12px;padding-right:24px;padding-left:24px" class="mceBlockContainer" align="center" valign="top">\r\n                                                    <table align="center" border="0" cellpadding="0" cellspacing="0" width="100%" style="max-width:282px" role="presentation" data-block-id="6" class="mceButtonContainer">\r\n                                                      <tbody>\r\n                                                        <tr><!--[if !mso]><!--></tr>\r\n                                                        <tr class="mceStandardButton">\r\n                                                          <td style="background-color:#000000;border-radius:8px;text-align:center" class="mceButton" valign="top"><a href="https://dev.to/devteam/tune-in-and-join-the-google-cloud-next-26-writing-challenge-1000-in-prizes-21bd?ahoy_click=true&t=7PYzwIKV1k9waajTLbYgjiEYZOje3ndX&s=-eoo1WOLuREfTamr7p0jShVp91jwBDWmNK9AuEyf3o0&u=https%253A%252F%252Fdev.to%252Fdevteam%252Ftune-in-and-join-the-google-cloud-next-26-writing-challenge-1000-in-prizes-21bd" target="_blank" class="mceButtonLink" style="backgro